package com.xoxo.pos.accounts;
import com.xoxo.pos.tables.BarTable;import jakarta.persistence.*;import java.math.BigDecimal;import java.time.LocalDateTime;import java.util.*;
@Entity @Table(name="accounts") public class Account{
@Id @GeneratedValue(strategy=GenerationType.IDENTITY) private Long id;@ManyToOne private BarTable barTable;@Column(nullable=false) private String customerName;@Enumerated(EnumType.STRING) private AccountStatus status=AccountStatus.OPEN;@Enumerated(EnumType.STRING) private PaymentMethod paymentMethod;private LocalDateTime openedAt;private LocalDateTime closedAt;@Column(precision=10,scale=2) private BigDecimal total=BigDecimal.ZERO;@Column(precision=10,scale=2) private BigDecimal totalCost=BigDecimal.ZERO;@Column(precision=10,scale=2) private BigDecimal grossProfit=BigDecimal.ZERO;private String notes;@OneToMany(mappedBy="account",cascade=CascadeType.ALL,orphanRemoval=true) private List<AccountItem> items=new ArrayList<>();
public Long getId(){return id;}public BarTable getBarTable(){return barTable;}public String getCustomerName(){return customerName;}public AccountStatus getStatus(){return status;}public PaymentMethod getPaymentMethod(){return paymentMethod;}public LocalDateTime getOpenedAt(){return openedAt;}public LocalDateTime getClosedAt(){return closedAt;}public BigDecimal getTotal(){return total;}public BigDecimal getTotalCost(){return totalCost;}public BigDecimal getGrossProfit(){return grossProfit;}public String getNotes(){return notes;}public List<AccountItem> getItems(){return items;}
public void setId(Long id){this.id=id;}public void setBarTable(BarTable barTable){this.barTable=barTable;}public void setCustomerName(String customerName){this.customerName=customerName;}public void setStatus(AccountStatus status){this.status=status;}public void setPaymentMethod(PaymentMethod paymentMethod){this.paymentMethod=paymentMethod;}public void setOpenedAt(LocalDateTime openedAt){this.openedAt=openedAt;}public void setClosedAt(LocalDateTime closedAt){this.closedAt=closedAt;}public void setTotal(BigDecimal total){this.total=total;}public void setTotalCost(BigDecimal totalCost){this.totalCost=totalCost;}public void setGrossProfit(BigDecimal grossProfit){this.grossProfit=grossProfit;}public void setNotes(String notes){this.notes=notes;}public void setItems(List<AccountItem> items){this.items=items;}}
